() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  // Extract all text content
  const bodyText = document.body.innerText;

  // Find conference name and acronym
  const titleEl = document.querySelector('h1, .page-title, .entry-title');
  const title = titleEl ? titleEl.innerText : '';

  // Find dates - look for deadline, notification, conference dates
  const dateElements = Array.from(document.querySelectorAll('p, li, div, span')).filter(el => {
    const text = el.innerText || el.textContent;
    return text && (
      text.includes('deadline') || 
      text.includes('Deadline') ||
      text.includes('notification') ||
      text.includes('Notification') ||
      text.includes('Conference dates') ||
      text.includes('conference dates') ||
      text.includes('2026')
    );
  });

  const dateTexts = dateElements.map(el => el.innerText.trim()).filter(t => t.length < 500);

  // Find topics
  const topicElements = Array.from(document.querySelectorAll('ul li, ol li')).map(el => el.innerText.trim());

  // Find submission URL
  const submissionLinks = Array.from(document.querySelectorAll('a')).filter(a => {
    const href = a.href || '';
    const text = a.innerText || '';
    return href.includes('easychair') || 
           href.includes('submit') || 
           text.toLowerCase().includes('submit') ||
           text.toLowerCase().includes('submission');
  });

  const submissionUrls = submissionLinks.map(a => ({
    url: a.href,
    text: a.innerText.trim()
  }));

  // Find location
  const locationMatch = bodyText.match(/Location[:\s]+([^\n]+)/i) || 
                       bodyText.match(/Venue[:\s]+([^\n]+)/i) ||
                       bodyText.match(/([A-Z][a-z]+,\s*[A-Z][a-z]+)/);

  // Find the main content section with dates
  let dateXPath = null;
  for (const el of dateElements) {
    const text = el.innerText;
    if (text.includes('deadline') || text.includes('Deadline')) {
      dateXPath = getXPath(el);
      break;
    }
  }

  // If no deadline element, try to find the main content section
  if (!dateXPath) {
    const mainContent = document.querySelector('main, article, .content, .entry-content');
    if (mainContent) {
      dateXPath = getXPath(mainContent);
    }
  }

  return {
    bodyText: bodyText,
    title: title,
    dateTexts: dateTexts,
    topicElements: topicElements,
    submissionUrls: submissionUrls,
    dateXPath: dateXPath,
    allLinks: Array.from(document.querySelectorAll('a')).map(a => ({
      href: a.href,
      text: a.innerText.trim()
    })).filter(l => l.text)
  };
}

