    }

    return "/" + parts.join("/");
  }

  // Find the Important Dates section
  const importantDatesSection = Array.from(document.querySelectorAll('*')).find(el => {
    const text = el.textContent || '';
    return text.includes('Submission Deadline') && text.includes('17 June 2026');
  });

  let dateXPath = null;
  if (importantDatesSection) {
    dateXPath = getXPath(importantDatesSection);
  }

  // Get all topics
  const topicsList = [];
  const topicsSection = Array.from(document.querySelectorAll('ul')).find(ul => {
    const text = ul.textContent || '';
    return text.includes('AI and Web Analytics') || text.includes('Web Mining');
  });

  if (topicsSection) {
    const items = topicsSection.querySelectorAll('li');
    items.forEach(li => {
      const text = li.textContent.trim();
      if (text && !text.includes('WISE') && text.length < 100) {
        topicsList.push(text);
      }
    });
  }

  // Find CMT link
  const cmtLink = Array.from(document.querySelectorAll('a')).find(a => {
    return a.href && a.href.includes('cmt');
  });

  // Check for conference location and dates in the page
  const bodyText = document.body.innerText;

  // Look for conference name
  const confNameMatch = bodyText.match(/WISE\s*2026/i);

  return {
    dateXPath: dateXPath,
    topics: topicsList,
    cmtUrl: cmtLink ? cmtLink.href : null,
    submissionDeadline: '17 June 2026',
    notificationDate: '20 July 2026',
    finalManuscriptDue: '25 August 2026',
    bodySnippet: bodyText.substring(0, 2000)
  };
}

() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  // Look for General Information link
  const genInfoLink = Array.from(document.querySelectorAll('a')).find(a => {
    const text = a.textContent || '';
    return text.trim() === 'General Information' || text.includes('About WISE');
  });

  // Check if there's any conference date/location info on current page
  const bodyText = document.body.innerText;

  // Look for dates pattern
  const datePattern = /(\d{1,2}[-–]\d{1,2}\s+\w+\s+2026)/g;
  const dates = bodyText.match(datePattern);

  // Look for location pattern
  const locationPattern = /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*,\s*[A-Z][a-z]+)/g;
  const locations = bodyText.match(locationPattern);

  // Find the Important Dates section more precisely
  const importantDatesHeading = Array.from(document.querySelectorAll('h1, h2, h3, h4')).find(h => {
    return h.textContent.includes('Important Dates');
  });

  let datesXPath = null;
  if (importantDatesHeading) {
    // Get the parent section
    let parent = importantDatesHeading.parentElement;
    while (parent && !parent.querySelector('*:contains("Submission Deadline")')) {
      parent = parent.parentElement;
      if (parent === document.body) break;
    }
    if (parent && parent !== document.body) {
      datesXPath = getXPath(parent);
    } else {
      datesXPath = getXPath(importantDatesHeading.parentElement);
    }
  }

  // If still not found, look for the div containing the dates
  if (!datesXPath) {
    const datesDiv = Array.from(document.querySelectorAll('div, section')).find(el => {
      const text = el.textContent || '';
      return text.includes('Submission Deadline') && 
             text.includes('17 June 2026') && 
             text.includes('Authors Notification') &&
             el.children.length > 0 &&
             el.children.length < 20;
    });
    if (datesDiv) {
      datesXPath = getXPath(datesDiv);
    }
  }

  return {
    genInfoUrl: genInfoLink ? genInfoLink.href : null,
    dates: dates,
    locations: locations,
    datesXPath: datesXPath,
    hasImportantDates: bodyText.includes('Important Dates'),
    bodyTextSample: bodyText.substring(1500, 2500)
  };
}
